// Synthetic SaaS user dataset — 200 records across four behavioural archetypes.
// Each record is generated by sampling from an archetype's feature distribution,
// then labelled by the *true* probability under our logistic model + a coin flip,
// so the dataset is internally consistent with the predictor.

import { predict, FEATURES } from './predictor.js'

const ARCHETYPES = [
  {
    name: 'POWER',
    weight: 0.18,
    means: { weekly_sessions: 20, avg_session_min: 45, features_used: 9, days_active_30: 24, content_created: 25, collaborators_invited: 4, paywall_hits: 6, tenure_days: 38, support_tickets: 0 },
    spread: 0.25
  },
  {
    name: 'ENGAGED',
    weight: 0.32,
    means: { weekly_sessions: 9, avg_session_min: 22, features_used: 6, days_active_30: 13, content_created: 8, collaborators_invited: 1, paywall_hits: 2, tenure_days: 26, support_tickets: 0 },
    spread: 0.35
  },
  {
    name: 'CURIOUS',
    weight: 0.30,
    means: { weekly_sessions: 4, avg_session_min: 12, features_used: 3, days_active_30: 6, content_created: 2, collaborators_invited: 0, paywall_hits: 0, tenure_days: 18, support_tickets: 0 },
    spread: 0.5
  },
  {
    name: 'DORMANT',
    weight: 0.20,
    means: { weekly_sessions: 1, avg_session_min: 4, features_used: 1, days_active_30: 1, content_created: 0, collaborators_invited: 0, paywall_hits: 0, tenure_days: 14, support_tickets: 1 },
    spread: 0.6
  }
]

// Tiny seedable PRNG so the dataset is stable across reloads (good for demos).
function mulberry32(seed) {
  return function () {
    let t = (seed += 0x6d2b79f5)
    t = Math.imul(t ^ (t >>> 15), t | 1)
    t ^= t + Math.imul(t ^ (t >>> 7), t | 61)
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296
  }
}

function pickArchetype(rand) {
  const r = rand()
  let acc = 0
  for (const a of ARCHETYPES) {
    acc += a.weight
    if (r <= acc) return a
  }
  return ARCHETYPES[ARCHETYPES.length - 1]
}

function noisyValue(mean, spread, rand, min, max) {
  // Symmetric noise around the mean, clamped to feature bounds.
  const jitter = (rand() - 0.5) * 2 * spread * (mean + 2)
  const v = Math.round(mean + jitter)
  return Math.max(min, Math.min(max, v))
}

const NAMES = [
  'AKARI', 'BENNO', 'CARA', 'DEVI', 'ELLIS', 'FINN', 'GRETA', 'HARU',
  'INDRA', 'JUNO', 'KAI', 'LENA', 'MIRA', 'NOVA', 'OREN', 'PRIYA',
  'QUIN', 'RAVI', 'SAGE', 'TARO', 'UMA', 'VIKA', 'WREN', 'XIAN',
  'YUKI', 'ZARA', 'ANIK', 'BIRK', 'CIRO', 'DEEN'
]

function makeId(i) {
  return 'U-' + String(1000 + i)
}

function makeName(rand, i) {
  return NAMES[Math.floor(rand() * NAMES.length)] + '-' + (i % 99).toString().padStart(2, '0')
}

export function generateDataset(n = 200, seed = 7) {
  const rand = mulberry32(seed)
  const rows = []
  for (let i = 0; i < n; i++) {
    const arch = pickArchetype(rand)
    const features = {}
    for (const f of FEATURES) {
      features[f.key] = noisyValue(arch.means[f.key], arch.spread, rand, f.min, f.max)
    }
    const probability = predict(features)
    const converted = rand() < probability ? 1 : 0
    rows.push({
      id: makeId(i),
      handle: makeName(rand, i),
      archetype: arch.name,
      probability,
      converted,
      ...features
    })
  }
  return rows
}

export function datasetStats(rows) {
  const n = rows.length
  if (!n) return { n: 0, conversionRate: 0, meanP: 0, hot: 0, warm: 0, cool: 0, cold: 0 }
  const sumP = rows.reduce((s, r) => s + r.probability, 0)
  const conv = rows.reduce((s, r) => s + r.converted, 0)
  const hot = rows.filter((r) => r.probability >= 0.7).length
  const warm = rows.filter((r) => r.probability >= 0.4 && r.probability < 0.7).length
  const cool = rows.filter((r) => r.probability >= 0.15 && r.probability < 0.4).length
  const cold = rows.filter((r) => r.probability < 0.15).length
  return { n, conversionRate: conv / n, meanP: sumP / n, hot, warm, cool, cold }
}
